/**
 * Returns nearby places of interest around the given coordinates using Google Places.
 * @summary List nearby points of interest
 */
export const getNearbyPlacesUrl = (params: NearbyPlacesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/streetview/places?${stringifiedParams}`
    : `/api/streetview/places`;
};

